// After Data Table (Run Once for All Items)
// INPUT: many items from Data Table (QUESTIONS + ANSWER)
// OUTPUT: ONE item with FAQs string (dynamic length)

const pickFirst = (obj, keys) => {
  for (const k of keys) {
    const v = obj?.[k];
    if (v !== undefined && v !== null && String(v).trim() !== "") {
      return String(v).trim();
    }
  }
  return "";
};

const rows = items
  .map(i => i.json)
  .map(r => ({
    q: pickFirst(r, ["QUESTIONS", "QUESTION", "Question", "question"]),
    a: pickFirst(r, ["ANSWER", "ANSWERS", "Answer", "answer"]),
  }))
  // remove empty rows + (optional) prevent cache row loops if you ever store __CACHE__
  .filter(r => r.q && r.a && r.q !== "__CACHE__");

const FAQs = rows
  .map(({ q, a }) => {
    // escape double quotes so your format stays consistent
    const qEsc = q.replace(/"/g, '\\"');
    const aEsc = a.replace(/"/g, '\\"');
    return `Question: "${qEsc}"\nAnswer: "${aEsc}"`;
  })
  .join("\n\n");

return [
  {
    json: {
      key: "PizzaDiDi_FAQs", // useful for saving/chunking later
      FAQs,
      rows: rows.length,
      chars: FAQs.length, // dynamic count
    },
  },
];

// Split into Chunks (Run Once for All Items)
// Use the *incoming* item directly (no need to reference $node)

const text = String($json.FAQs ?? "");
const chunkSize = 1500; // change if needed
const key = String($json.key ?? "PizzaDiDi_FAQs");

if (!Number.isFinite(chunkSize) || chunkSize <= 0) {
  throw new Error("chunkSize must be a positive number");
}

const out = [];
let part = 1;

for (let i = 0; i < text.length; i += chunkSize) {
  out.push({
    json: {
      key,
      part,
      value: text.slice(i, i + chunkSize),
    },
  });
  part++;
}

return out;

// n8n Code node (Run Once for All Items)

// 1) Pull ALL rows from Google Sheets node
const sheetItems = $items("Google Sheets").map(i => i.json);

// 2) Pull ALL rows from Data Table list node
const tableItems = $items("Data Table - List").map(i => i.json);

// Helpers
const norm = (s) => String(s ?? "")
  .trim()
  .replace(/\s+/g, " ")
  .toLowerCase();

// --- Build a map of Sheet rows keyed by normalized question ---
const sheetMap = new Map();

// If there are duplicates in sheet, last one wins (you can change this behavior)
for (const r of sheetItems) {
  const qRaw = r.QUESTION ?? r.Questions ?? r.QUESTIONS ?? "";
  const aRaw = r.ANSWER ?? r.Answers ?? r.ANSWERs ?? r.ANSWER ?? "";

  const q = String(qRaw).trim();
  const a = String(aRaw).trim();
  if (!q || !a) continue;

  sheetMap.set(norm(q), { QUESTIONS: q, ANSWER: a });
}

// --- Build a map of Data Table rows keyed by normalized question ---
const tableMap = new Map();
for (const r of tableItems) {
  const q = r.QUESTIONS ?? "";
  const key = norm(q);
  if (!key) continue;
  tableMap.set(key, { id: r.id, QUESTIONS: String(q).trim(), ANSWER: String(r.ANSWER ?? "").trim() });
}

// Actions array: upserts + deletes
const actions = [];

// A) Upsert: everything in sheetMap should exist in Data Table
for (const [key, sRow] of sheetMap.entries()) {
  // include id if it exists (helps some setups), but Upsert should use QUESTIONS as unique key
  const existing = tableMap.get(key);

  actions.push({
    json: {
      action: "upsert",
      // keep original casing from sheet
      QUESTIONS: sRow.QUESTIONS,
      ANSWER: sRow.ANSWER,
      // optional: if you want to carry id
      existing_id: existing?.id ?? null
    }
  });
}

// B) Delete: everything in tableMap NOT in sheetMap should be deleted
for (const [key, tRow] of tableMap.entries()) {
  if (!sheetMap.has(key)) {
    actions.push({
      json: {
        action: "delete",
        id: tRow.id,
        QUESTIONS: tRow.QUESTIONS
      }
    });
  }
}

return actions;
